import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, getDocs, updateDoc } from 'firebase/firestore';

function TeamLineup() {
  const { teamId } = useParams();
  const navigate = useNavigate();

  const [teamData, setTeamData] = useState(null);
  const [players, setPlayers] = useState([]);
  const [lineup, setLineup] = useState([]);
  const [selectedSlotIndex, setSelectedSlotIndex] = useState(null);
  const [showPlayerSelection, setShowPlayerSelection] = useState(false);
  const [pinVerified, setPinVerified] = useState(false);

  // Fetch team and player data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const teamRef = doc(db, 'teams', teamId);
        const teamSnap = await getDoc(teamRef);

        if (!teamSnap.exists()) {
          alert('Team not found');
          navigate('/teams-management');
          return;
        }

        const team = teamSnap.data();
        setTeamData(team);

        // Set saved lineup or empty slots
        const validPlayerIds = (team.players || []).filter(id => id);
        if (validPlayerIds.length > 0) {
          const playerRefs = await Promise.all(
            validPlayerIds.map(playerId => getDoc(doc(db, 'players', playerId)))
          );
          const savedPlayers = playerRefs.map(ref => ref.exists() ? { id: ref.id, ...ref.data() } : null);
          setLineup(savedPlayers);
        } else {
          setLineup(Array(team.playerCount).fill(null));
        }

        const playersSnap = await getDocs(collection(db, 'players'));
        const playersData = playersSnap.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        }));
        setPlayers(playersData);

      } catch (error) {
        console.error('Error fetching data:', error);
        alert('Failed to load data.');
        navigate('/teams-management');
      }
    };

    fetchData();
  }, [teamId, navigate]);

  // PIN Verification
  useEffect(() => {
    if (teamData && !pinVerified) {
      const userPin = prompt("Enter PIN to access the lineup:");
      if (userPin === teamData.pin) {
        setPinVerified(true);
      } else {
        alert("Incorrect PIN. Access denied.");
        navigate('/teams-management');
      }
    }
  }, [teamData, pinVerified, navigate]);

  // Open player selection
  const handleSelectPlayer = (index) => {
    setSelectedSlotIndex(index);
    setShowPlayerSelection(true);
  };

  // Assign player to a slot
  const assignPlayerToSlot = (player) => {
    const updatedLineup = [...lineup];
    updatedLineup[selectedSlotIndex] = player;
    setLineup(updatedLineup);
    setShowPlayerSelection(false);
  };

  // Save lineup to Firestore
  const handleSaveLineup = async () => {
    try {
      const selectedPlayers = lineup.map(player => (player ? player.id : null));

      const teamRef = doc(db, 'teams', teamId);
      await updateDoc(teamRef, {
        players: selectedPlayers,
      });

      alert('Lineup saved successfully!');
    } catch (error) {
      console.error('Error saving lineup:', error);
      alert('Failed to save lineup.');
    }
  };

  if (!teamData || !pinVerified) {
    return <p>Loading...</p>;
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>{teamData.name} - Lineup</h1>

      <img
        src={`${process.env.PUBLIC_URL}/images/Tactics/${teamData.playerCount}_players_${teamData.tactic}.png`}
        alt="Tactic"
        style={styles.tacticImage}
      />

      <div style={styles.lineupContainer}>
        {lineup.map((player, index) => (
          <div
            key={index}
            style={styles.slot}
            onClick={() => handleSelectPlayer(index)}
          >
            {player ? (
              <>
                <img
                  src={player.profilePicture || `${process.env.PUBLIC_URL}/images/default_profile_picture.png`}
                  alt="Player"
                  style={styles.playerImage}
                />
                <p style={styles.playerName}>{player.lastName}, {player.firstName}</p>
                <p style={styles.playerPosition}>{player.favoritePosition}</p>
                <p style={styles.playerPower}>Power: {player.powerRating}</p>
              </>
            ) : (
              <p style={styles.emptySlot}>+ Slot {index + 1}</p>
            )}
          </div>
        ))}
      </div>

      {showPlayerSelection && (
        <div style={styles.overlay}>
          <div style={styles.playerSelectionContainer}>
            <h3>Select a Player</h3>
            <div style={styles.playerGrid}>
              {players.map((player) => (
                <div
                  key={player.id}
                  style={styles.playerCard}
                  onClick={() => assignPlayerToSlot(player)}
                >
                  <img
                    src={player.profilePicture || `${process.env.PUBLIC_URL}/images/default_profile_picture.png`}
                    alt="Player"
                    style={styles.playerCardImage}
                  />
                  <p>{player.lastName}, {player.firstName}</p>
                  <p>{player.favoritePosition}</p>
                  <p>Power: {player.powerRating}</p>
                </div>
              ))}
            </div>
            <button style={styles.closeButton} onClick={() => setShowPlayerSelection(false)}>
              Cancel
            </button>
          </div>
        </div>
      )}

      <button style={styles.saveButton} onClick={handleSaveLineup}>
        Save Lineup
      </button>

      <button style={styles.backButton} onClick={() => navigate('/teams-management')}>
        Back to Teams Management
      </button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  title: {
    fontSize: '24px',
    marginBottom: '20px',
    color: '#293F14',
  },
  tacticImage: {
    width: '50%',
    height: 'auto',
    marginBottom: '30px',
  },
  lineupContainer: {
    display: 'flex',
    gap: '20px',
  },
  slot: {
    width: '120px',
    height: '160px',
    backgroundColor: '#7FC6A4',
    borderRadius: '10px',
    cursor: 'pointer',
    textAlign: 'center',
  },
  playerCard: {
    width: '120px',
    height: '160px',
    backgroundColor: '#293F14',
    color: '#FFFFFF',
    borderRadius: '10px',
    textAlign: 'center',
    padding: '10px',
    cursor: 'pointer',
  },
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    backgroundColor: 'rgba(0,0,0,0.9)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },
  saveButton: {
    backgroundColor: '#386C0B',
    padding: '10px 20px',
    color: '#FFF',
    marginTop: '20px',
  },
};

export default TeamLineup;
